// 公式居中对齐，公式编号右对齐
var doc = Application.ActiveDocument;
var range = doc.Content;
var formulas = range.Fields; // 获取所有域（公式通常以域形式存在）

var count = 0;
for (var i = 1; i <= formulas.Count; i++) {
    var field = formulas.Item(i);
    try {
        // 判断是否为公式域（EQ 域）
        if (field.Type === 3) { // wdFieldEQ = 3
            var para = field.ParentRange.Paragraphs(1);

            // 公式本身居中
            para.Alignment = 1; // wdAlignParagraphCenter = 1

            // 如果段落中包含编号（通常在公式后），需要特殊处理
            // 这里简单处理：将公式所在段落设为居中
            // 如需更复杂的公式 + 编号布局，可能需要表格或制表位

            count++;
        }
    } catch (e) {
        // 跳过错误
    }
}

return { success: true, message: "已处理 " + count + " 个公式域", formulaCount: count };

// 查找文档中的公式段落（通常包含"="或特殊公式标记）
var doc = Application.ActiveDocument;
var content = doc.Content;

// 获取所有段落
var paras = content.Paragraphs;
var formulaParas = [];

for (var i = 1; i <= paras.Count; i++) {
    var para = paras.Item(i);
    var text = para.Range.Text;

    // 检测是否可能是公式段落（包含等号、积分符号、求和符号等）
    if (text.indexOf("=") !== -1 || 
        text.indexOf("∫") !== -1 || 
        text.indexOf("∑") !== -1 ||
        text.indexOf("√") !== -1 ||
        text.indexOf("π") !== -1 ||
        text.indexOf("α") !== -1 ||
        text.indexOf("β") !== -1 ||
        text.indexOf("γ") !== -1 ||
        text.indexOf("δ") !== -1 ||
        text.indexOf("ε") !== -1 ||
        text.indexOf("λ") !== -1 ||
        text.indexOf("μ") !== -1 ||
        text.indexOf("σ") !== -1 ||
        text.indexOf("ω") !== -1 ||
        text.indexOf("→") !== -1 ||
        text.indexOf("←") !== -1 ||
        text.indexOf("↑") !== -1 ||
        text.indexOf("↓") !== -1 ||
        text.indexOf("∞") !== -1 ||
        text.indexOf("≈") !== -1 ||
        text.indexOf("≠") !== -1 ||
        text.indexOf("≤") !== -1 ||
        text.indexOf("≥") !== -1 ||
        text.indexOf("×") !== -1 ||
        text.indexOf("÷") !== -1 ||
        text.indexOf("²") !== -1 ||
        text.indexOf("³") !== -1 ||
        text.match(/\(.*\d+\)/)) { // 匹配类似 (1)、(2-1) 的编号

        formulaParas.push({
            index: i,
            text: text.substring(0, Math.min(50, text.length)) + "..."
        });
    }
}

return { 
    success: true, 
    totalParagraphs: paras.Count,
    formulaCount: formulaParas.length,
    sampleFormulas: formulaParas.slice(0, 10) // 返回前 10 个示例
};
